import{_ as o,o as a,c as r,ai as e}from"./chunks/framework.DMjte4z8.js";const g=JSON.parse('{"title":"多人地图入门：联机为什么和单机不一样","description":"","frontmatter":{"title":"多人地图入门：联机为什么和单机不一样","category":"rpg-systems","updated":"2026-05-07T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.79,"discovered_via":"manual","sources":["https://blog.csdn.net/gitblog_00249/article/details/160763508","https://doc.quark.cn/preview/tongyongshenghuo-qita-qita/F98DC1C4421D2B8033857E8D4FA60615","https://tieba.baidu.com/p/5178852824","https://www.ali213.net/zt/war3re/","https://dl.3dmgame.com/pc/147516.html"]},"headers":[],"relativePath":"rpg-systems/多人地图入门联机为什么和单机不一样.md","filePath":"rpg-systems/多人地图入门联机为什么和单机不一样.md","lastUpdated":1778132689000}'),n={name:"rpg-systems/多人地图入门联机为什么和单机不一样.md"};function l(s,t,i,u,h,q){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="多人地图入门-联机为什么和单机不一样" tabindex="-1">多人地图入门：联机为什么和单机不一样 <a class="header-anchor" href="#多人地图入门-联机为什么和单机不一样" aria-label="Permalink to “多人地图入门：联机为什么和单机不一样”">​</a></h1><h2 id="什么是多人游戏-为什么不一样" tabindex="-1">什么是多人游戏？为什么不一样？ <a class="header-anchor" href="#什么是多人游戏-为什么不一样" aria-label="Permalink to “什么是多人游戏？为什么不一样？”">​</a></h2><p>本节将帮助你理解单机地图和多人联机地图的本质区别。学完本节后，你会明白为什么一张能完美单机运行的地图，联机时却会出现各种奇怪的bug。</p><h3 id="玩家数量不是唯一的区别" tabindex="-1">玩家数量不是唯一的区别 <a class="header-anchor" href="#玩家数量不是唯一的区别" aria-label="Permalink to “玩家数量不是唯一的区别”">​</a></h3><p>很多新手以为，多人游戏只是&quot;多了几个玩家一起玩&quot;这么简单。这种想法会让你在制作联机地图时吃大亏！</p><p><strong>单机游戏</strong>的运行逻辑很简单：你的电脑扮演&quot;唯一的大脑&quot;，所有的游戏规则、单位行为、伤害计算都在你这台电脑上完成。就像一个人唱独角戏，指挥起来当然轻松。</p><p><strong>多人联机游戏</strong>则完全不同。想象一下，几个朋友各自坐在不同的电脑前，但大家必须看到完全一样的画面、做出一致的操作。这就像让几个乐队同时演奏同一首曲子——每个人都需要知道&quot;现在该演奏什么&quot;，而且必须完全同步！[^5]</p><p>这意味着，在多人游戏中，所有玩家的电脑都需要&quot;知道&quot;地图上发生了什么。地图制作者必须确保每一个计算结果、每一个触发事件都能正确地同步给所有玩家。</p><h3 id="为什么你的单机地图联机会出错" tabindex="-1">为什么你的单机地图联机会出错 <a class="header-anchor" href="#为什么你的单机地图联机会出错" aria-label="Permalink to “为什么你的单机地图联机会出错”">​</a></h3><p>如果你按照单机思路做了一张地图，直接发给朋友联机，很可能遇到这些问题：</p><ol><li><strong>&quot;看不到队友的操作&quot;</strong> — 你的触发器只在你的电脑上执行，别人的电脑根本不知道发生了什么</li><li><strong>&quot;单位突然瞬移&quot;</strong> — 位置信息没有正确同步</li><li><strong>&quot;有人退出后地图崩溃&quot;</strong> — 没有处理&quot;玩家离开&quot;的情况</li><li><strong>&quot;伤害计算不一致&quot;</strong> — 每个人算出的伤害不一样</li></ol><blockquote><p><strong>💡 新手提示</strong>：把&quot;同步&quot;想象成&quot;现场直播&quot;。在单机游戏中，你是录像师，可以随时暂停、回放、剪辑。但在多人游戏中，你必须做&quot;直播&quot;——所有玩家必须同时看到完全相同的画面，一帧都不能差。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手以为只要在地图里加几个&quot;玩家&quot;设置就能联机了。实际上，你还需要专门编写&quot;多人同步逻辑&quot;，告诉地图&quot;当某个事件发生时，如何把这个变化通知给所有玩家的电脑&quot;。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>现在你应该理解了：多人地图的核心挑战不是&quot;人多&quot;，而是<strong>同步</strong>。制作联机地图时，你必须时刻思考：&quot;如果我现在做这个操作，其他玩家的电脑能知道吗？他们的画面会变成什么样？&quot;</p><p>记住这个原则，你的联机地图就已经迈出了正确的一步！</p><h2 id="网络同步-多人游戏的核心机制" tabindex="-1">网络同步：多人游戏的核心机制 <a class="header-anchor" href="#网络同步-多人游戏的核心机制" aria-label="Permalink to “网络同步：多人游戏的核心机制”">​</a></h2><p>本节将带你理解什么是&quot;网络同步&quot;，以及为什么联机游戏比单机游戏复杂得多。学完本节后，你会明白为什么制作多人地图需要特别注意同步问题[^1]。</p><h3 id="什么是同步-sync" tabindex="-1">什么是同步（Sync）？ <a class="header-anchor" href="#什么是同步-sync" aria-label="Permalink to “什么是同步（Sync）？”">​</a></h3><p><strong>同步（Sync）</strong> 是指让所有联网玩家在同一时刻看到完全相同的游戏画面和状态。简单来说，就是&quot;大家看到的东西必须一样&quot;。</p><blockquote><p><strong>💡 新手提示</strong>：你可以把同步想象成所有人一起看同一场足球直播——如果网络不好，你看到的进球可能比别人晚几秒，这在游戏中就是&quot;不同步&quot;了。</p></blockquote><h3 id="为什么所有玩家必须看到相同结果" tabindex="-1">为什么所有玩家必须看到相同结果？ <a class="header-anchor" href="#为什么所有玩家必须看到相同结果" aria-label="Permalink to “为什么所有玩家必须看到相同结果？”">​</a></h3><p>在<strong>单人游戏</strong>中，只有你自己的电脑在计算和显示游戏内容，所以永远不会出现&quot;画面不一致&quot;的问题。</p><p>但在<strong>多人游戏</strong>中，情况完全不同：</p><ol><li><strong>每台电脑都在独立计算</strong> — 当你操控英雄移动时，你的电脑在计算；其他玩家的电脑也在同时计算</li><li><strong>如果不同步会怎样？</strong> — 你看到怪物A在左边，队友可能看到怪物A在右边；你打了怪物100血，队友那边可能只掉了50血</li><li><strong>游戏会彻底乱套</strong> — 最终导致无法正常游戏，甚至直接崩溃[^5]</li></ol><p>这就是为什么制作多人地图时，所有的触发器（游戏规则脚本）和游戏逻辑都必须经过特殊设计，确保每一步计算结果在所有玩家的电脑上完全一致。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手最常犯的错误是，在触发器里使用了&quot;随机数&quot;或&quot;获取当前鼠标位置&quot;这类在不同电脑上会产生不同结果的功能，而没有做任何同步处理。这样制作出来的地图，单机测试完全正常，但联机时就会Bug满天飞。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成本节学习后，你应该理解：</p><ul><li><strong>同步</strong> = 所有玩家看到相同游戏状态</li><li><strong>不同步的后果</strong> = 画面混乱、游戏崩溃、无法正常联机</li><li><strong>制作多人地图的核心原则</strong> = 任何影响游戏结果的计算，都必须保证所有玩家的电脑得到相同结果</li></ul><blockquote><p><strong>💡 新手提示</strong>：在制作多人地图时，每写完一个触发器，都先问自己：&quot;这个触发器在每个玩家的电脑上会得到一样的结果吗？&quot;如果答案是否定的，就需要修改或添加同步处理。</p></blockquote><h2 id="触发器在多人游戏中的关键差异" tabindex="-1">触发器在多人游戏中的关键差异 <a class="header-anchor" href="#触发器在多人游戏中的关键差异" aria-label="Permalink to “触发器在多人游戏中的关键差异”">​</a></h2><p>本节将解释多人联机时触发器的工作方式与单机的关键区别。学完本节后，你能理解为什么同样的触发器在单机正常但在联机时会出错，并学会正确选择触发器的执行方式。</p><h3 id="理解bj函数的安全隐患" tabindex="-1">理解BJ函数的安全隐患 <a class="header-anchor" href="#理解bj函数的安全隐患" aria-label="Permalink to “理解BJ函数的安全隐患”">​</a></h3><p>BJ函数（Blizzard JASS函数）是暴雪官方提供的&quot;简化版&quot;函数库，它们把复杂的代码包装成容易理解的命令，比如<code>CreateUnitAtLoc</code>就是&quot;在某个位置创建一个单位&quot;。在单人地图中，BJ函数完全够用；但在多人联机时，它们可能成为噩梦的开始。</p><p>BJ函数之所以不安全，是因为它们<strong>内部使用了&quot;随机&quot;或&quot;当前玩家&quot;等模糊设定</strong>。例如，当你用BJ函数创建一个单位时，它可能偷偷使用了&quot;触发玩家&quot;（也就是当前操作者）作为所属玩家。在单机中这没问题，但在联机中，不同玩家触发同一事件时，单位可能创建在错误的位置或属于错误的玩家，导致<strong>不同步（Desync）问题</strong>——即所有玩家的游戏画面开始出现差异。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手很喜欢用<code>Unit - Create unit</code>这类BJ函数创建单位，觉得简单。但在多人地图中，建议改用<code>Unit - Create Unit At Position</code>（指定精确坐标），并明确填写所属玩家变量。不要相信&quot;触发玩家&quot;这种会自动判断的功能——联机时它可能判断错误。</p></blockquote><h3 id="本地执行与全局执行的选择" tabindex="-1">本地执行与全局执行的选择 <a class="header-anchor" href="#本地执行与全局执行的选择" aria-label="Permalink to “本地执行与全局执行的选择”">​</a></h3><p>在触发编辑器中，每个事件/动作都有&quot;本地&quot;和&quot;全局&quot;两种执行模式。这是多人游戏中最容易被忽视、也最容易导致问题的设置。</p><p><strong>全局执行</strong>意味着这个触发器会在<strong>所有玩家的电脑上同时运行</strong>。所有玩家看到的游戏状态必须完全一致，这是联机同步的基础。<strong>本地执行</strong>则只会在<strong>触发事件的玩家电脑上运行</strong>，其他玩家完全不知道发生了什么。</p><p>举一个具体例子：假设你设计了一个&quot;按ESC键打开商店&quot;的触发器。如果你设置成全局执行，所有玩家同时打开商店——没问题。但如果你设置成本地执行，只有按ESC的那个玩家能看到商店，其他玩家还以为游戏卡住了。</p><blockquote><p><strong>💡 新手提示</strong>：大部分情况下，多人游戏的触发器都应该是&quot;全局执行&quot;。只有当你确实需要&quot;只有我能看到&quot;的UI（比如玩家个人菜单）时，才考虑本地执行。养成习惯：创建新触发器时，先检查执行方式是否为全局。</p></blockquote><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><strong>打开触发编辑器</strong> — 双击触发器列表中的任意触发器，或在工具栏点击闪电图标[^2]</li><li><strong>找到执行条件设置</strong> — 在触发器属性面板中，查看&quot;执行&quot;（Execution）选项</li><li><strong>确认选择&quot;全局&quot;</strong> — 确保勾选了&quot;全局执行&quot;（Global），特别是在创建单位、移动单位、修改属性等操作时</li><li><strong>测试联机同步</strong> — 创建地图后，邀请朋友局域网联机，观察是否出现画面不一致[^5]</li></ol><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你已经理解了BJ函数在多人环境中的风险，并掌握了检查触发器执行方式的方法。记住这个原则：<strong>多人地图中，所有涉及游戏状态的触发器都要用全局执行；只有纯UI展示类的才考虑本地执行</strong>。养成每次创建触发器都检查执行方式的习惯，能避免80%的联机崩溃问题。</p><h2 id="常见的联机崩溃与报错" tabindex="-1">常见的联机崩溃与报错 <a class="header-anchor" href="#常见的联机崩溃与报错" aria-label="Permalink to “常见的联机崩溃与报错”">​</a></h2><p>在本节中，我们将认识联机时最让人头疼的问题——<strong>Desync（同步失败）</strong>，以及哪些操作最容易导致你的联机地图崩溃。学完本节，你将能够识别常见的联机错误，并写出更稳定的联机兼容地图。</p><h3 id="什么是desync-同步失败" tabindex="-1">什么是Desync（同步失败） <a class="header-anchor" href="#什么是desync-同步失败" aria-label="Permalink to “什么是Desync（同步失败）”">​</a></h3><p><strong>Desync</strong>是&quot;Desynchronization&quot;的缩写，中文叫&quot;同步失败&quot;[^1]。这是联机游戏中最常见、也最让人头疼的问题。</p><p>打个比方：想象你和朋友视频通话，但网络卡了——你说的内容和朋友听到的内容对不上。Desync就是这个道理。在War3联机时，每个玩家的电脑实际上都在独立运行游戏，通过网络同步数据[^2]。当某个操作导致某个玩家的游戏状态和其他人不一样时，就会发生Desync。</p><p>Desync的典型表现包括：</p><ul><li>你看到单位在某个位置，但别人看到它在另一个位置</li><li>某个技能明明释放了，但只有部分玩家看到效果</li><li>游戏突然崩溃，弹出错误提示</li></ul><h3 id="最容易导致联机问题的操作" tabindex="-1">最容易导致联机问题的操作 <a class="header-anchor" href="#最容易导致联机问题的操作" aria-label="Permalink to “最容易导致联机问题的操作”">​</a></h3><h4 id="_1-使用-获取随机整数-直接作为条件" tabindex="-1">1. 使用&quot;获取随机整数&quot;直接作为条件 <a class="header-anchor" href="#_1-使用-获取随机整数-直接作为条件" aria-label="Permalink to “1. 使用&quot;获取随机整数&quot;直接作为条件”">​</a></h4><p>随机数是Desync的&quot;重灾区&quot;[^3]。当你在触发器里直接写&quot;如果(获取随机整数(1到100))大于50&quot;，每个玩家的电脑会生成不同的随机数！玩家A的结果是60（大于50），玩家B的结果是40（小于50），游戏立刻就不同步了。</p><p><strong>正确的做法</strong>：</p><ol><li>先用一个&quot;整数&quot;类型的变量储存随机数（设置变量 &gt; 随机数 = 获取随机整数(1到100)）</li><li>然后再判断这个变量</li></ol><h4 id="_2-在触发器里使用-等待-动作" tabindex="-1">2. 在触发器里使用&quot;等待&quot;动作 <a class="header-anchor" href="#_2-在触发器里使用-等待-动作" aria-label="Permalink to “2. 在触发器里使用&quot;等待&quot;动作”">​</a></h4><p>&quot;等待&quot;是新手最爱用的功能，但它在联机时是<strong>定时炸弹</strong>[^4]。因为每个玩家的电脑速度不同，等待1秒后，每个人的实际执行时间都会有细微差别。累积下来，触发器的执行顺序就会错乱。</p><p><strong>正确做法</strong>：使用&quot;定时器&quot;代替等待，用&quot;周期性事件&quot;来控制时间循环。</p><h4 id="_3-用-获取点击位置-直接作为施法位置" tabindex="-1">3. 用&quot;获取点击位置&quot;直接作为施法位置 <a class="header-anchor" href="#_3-用-获取点击位置-直接作为施法位置" aria-label="Permalink to “3. 用&quot;获取点击位置&quot;直接作为施法位置”">​</a></h4><p>当技能需要玩家选择目标位置时，直接使用&quot;获取点击位置&quot;也可能导致不同步。更好的做法是：先让玩家选择位置，保存到一个&quot;点&quot;变量里，然后所有后续操作都使用这个变量。</p><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手觉得&quot;等待&quot;简单又好用，但联机时这是Desync最常见的元凶之一！如果你的地图需要延迟执行某个动作，一定要用&quot;定时器&quot;而不是&quot;等待&quot;。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：写完触发器后，先用<strong>局域网联机测试</strong>几遍，而不是只在自己电脑上测试。很多Desync问题只有在多人环境下才会暴露。</p></blockquote><hr><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>学完本节，你应该掌握了：</p><ul><li>✅ 理解什么是Desync（同步失败）</li><li>✅ 知道随机数、等待、点击位置是三大&quot;雷区&quot;</li><li>✅ 学会用变量储存随机数和位置，避免直接使用</li></ul><p>建议：用你的小地图创建一个简单的双人测试场景，故意用这些&quot;危险操作&quot;，观察什么时候会出问题。亲身体验比看十遍理论记得更清楚！</p><h2 id="如何测试你的多人地图" tabindex="-1">如何测试你的多人地图 <a class="header-anchor" href="#如何测试你的多人地图" aria-label="Permalink to “如何测试你的多人地图”">​</a></h2><p>本节你将学会如何测试多人地图，确保你的多人功能（玩家控制、单位、触发器等）在实际联机时能正常工作。</p><h3 id="使用局域网-lan-测试" tabindex="-1">使用局域网（LAN）测试 <a class="header-anchor" href="#使用局域网-lan-测试" aria-label="Permalink to “使用局域网（LAN）测试”">​</a></h3><p>多人地图不能用普通方式&quot;测试游戏&quot;来检查，因为普通测试只有一个玩家。多人地图需要多个&quot;玩家槽位&quot;同时存在才能验证功能是否正常[^5]。这时候就需要用<strong>局域网（LAN）</strong>来模拟联机环境。</p><h3 id="如何模拟多个玩家" tabindex="-1">如何模拟多个玩家 <a class="header-anchor" href="#如何模拟多个玩家" aria-label="Permalink to “如何模拟多个玩家”">​</a></h3><p>在同一台电脑上模拟多人游戏，是最简单省时的测试方法。</p><h3 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><strong>打开游戏主程序</strong> — 双击桌面图标或开始菜单启动魔兽争霸 III[^5]</li><li><strong>进入多人游戏菜单</strong> — 在主菜单选择&quot;多人游戏&quot;选项</li><li><strong>选择局域网模式</strong> — 点击&quot;局域网对战&quot;进入联机界面</li><li><strong>创建主机</strong> — 选择&quot;创建游戏&quot;，在地图列表中找到并选择你的地图文件（.w3x格式）</li><li><strong>设置玩家数量</strong> — 在创建窗口调整&quot;玩家数量&quot;或&quot;可用队伍&quot;数量</li><li><strong>启动第二个游戏窗口</strong> — 回到桌面，再次双击魔兽争霸 III 图标打开第二个游戏窗口</li><li><strong>加入游戏</strong> — 在第二个窗口进入&quot;局域网对战&quot;，你应该能看到刚才创建的房间，点击加入</li></ol><blockquote><p><strong>💡 新手提示</strong>：每次双击游戏图标就会打开一个新的游戏窗口，可以无限创建多个&quot;假玩家&quot;来测试你的地图！</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记第二步——必须重新打开一个新的游戏窗口，而不是在同一个窗口里操作。 Warcraft III 不允许在单人测试模式下模拟多个玩家。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能看到<strong>两个（或多个）游戏窗口同时运行</strong>，每个窗口代表一个独立的玩家。你可以用鼠标在不同窗口间切换，模拟不同玩家操作，从而验证你的多人触发器、单位能力和游戏逻辑是否正常工作。如果发现问题，回到触发器编辑器检查相关条件判断。</p><h2 id="多人地图设计入门建议" tabindex="-1">多人地图设计入门建议 <a class="header-anchor" href="#多人地图设计入门建议" aria-label="Permalink to “多人地图设计入门建议”">​</a></h2><p>本节将帮助你了解设计多人地图时的核心思路，以及如何让你的地图同时兼顾单机和联机玩家的体验。学完本节后，你将知道在地图设计初期应该考虑哪些关键问题，避免后期大规模返工。</p><h3 id="操作步骤-2" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-2" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：明确你的地图定位</strong> — 在开始画地形之前，先问自己：这个地图主要是给一个人玩的单人冒险，还是多人合作/对抗？可以在地图说明文档中写下设计目标，这能帮助你在后续制作中做出统一的选择[^2]。</p></li><li><p><strong>第二步：从多人角度思考触发器逻辑</strong> — 触发器（也叫触发编辑器）是控制游戏事件的核心工具，比如“单位死亡时增加积分”这类规则[^2]。在编写触发器时，不要只考虑玩家1（红色玩家），要使用“当前触发玩家”或“任意玩家”这类通用条件，这样代码才能同时适配所有玩家的操作。</p></li><li><p><strong>第三步：避免使用硬编码的玩家编号</strong> — 新手常犯的错误是在触发器里直接写“玩家1造了单位就加钱”，正确做法是使用变量（如“触发玩家”）来替代具体玩家编号[^2]。这样当玩家2、玩家3进入游戏时，相同的逻辑才能正常运作。</p></li><li><p><strong>第四步：测试时模拟多人环境</strong> — 完成基础功能后，不要只测试单机流程。使用编辑器内置的“模拟玩家”功能，或者局域网联机测试，让至少两个玩家同时操作，观察是否有报错或逻辑混乱[^5]。</p></li><li><p><strong>第五步：平衡单人任务和多人对战的内容</strong> — 如果你的地图有剧情任务又支持联机，记得把PVE（玩家对环境/电脑）内容和PVP（玩家对玩家）内容分开设计。可以在地图中设置不同的游戏模式选项，让玩家自由选择[^2]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：多人地图的难度设计要比重构友好很多——先确保多人能正常运行，再去优化单人体验。多人兼容问题发现得越晚，修复成本越高。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手以为“先做单人模式，等做完再加多人支持就行了”，结果发现触发器需要全部重写。建议从一开始就用通用变量编写触发器，即使单人测试也用“当前玩家”而不是固定玩家编号。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你已经掌握了多人地图设计的基本思路：在设计初期就以多人兼容为前提，使用通用变量编写触发器，并通过实际联机测试发现问题。遵循这些原则，你的地图在开发后期会少走很多弯路。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://blog.csdn.net/gitblog_00249/article/details/160763508" target="_blank" rel="noreferrer">终极魔兽争霸III地图编辑器：HiveWE 完整指南与实战教程-CSDN博客</a> — accessed 2026-05-07 [^2]: <a href="https://doc.quark.cn/preview/tongyongshenghuo-qita-qita/F98DC1C4421D2B8033857E8D4FA60615" target="_blank" rel="noreferrer">《魔兽争霸Ⅲ》地图制作入门教程 - doc.quark.cn</a> — accessed 2026-05-07 [^3]: <a href="https://tieba.baidu.com/p/5178852824" target="_blank" rel="noreferrer">魔兽地图编辑器入门教学：从零开始制作</a> — accessed 2026-05-07 [^4]: <a href="https://www.ali213.net/zt/war3re/" target="_blank" rel="noreferrer">魔兽争霸3：重制版_魔兽争霸3：重制版下载_魔兽争霸3：重制版攻略专题...</a> — accessed 2026-05-07 [^5]: <a href="https://dl.3dmgame.com/pc/147516.html" target="_blank" rel="noreferrer">《魔兽争霸3：重制版》下载-3DM单机</a> — accessed 2026-05-07</p>',92)])])}const p=o(n,[["render",l]]);export{g as __pageData,p as default};
